/* Labor rate multipliers by region */
function getMultiplier(region) {
  const m = { northeast: 1.35, west: 1.30, midwest: 0.95, south: 0.90, southeast: 0.92, mountain: 1.05 };
  return m[region] || 1.0;
}

function fmtDollar(n) { return "$" + n.toLocaleString(); }

